import { GoldRushClient } from "@covalenthq/client-sdk";

const client = new GoldRushClient(process.env.GOLDRUSH_API_KEY);

async function getTreasuryIntelligence(chainName, treasuryAddress) {
  const [balances, txns] = await Promise.all([
    client.BalanceService.getTokenBalancesForWalletAddress(chainName, treasuryAddress),
    client.TransactionService.getTransactionsForAddressV3(chainName, treasuryAddress),
  ]);
  const totalUSD = (balances.data?.items ?? []).reduce((s, i) => s + (i.quote ?? 0), 0);
  return { totalUSD, assets: balances.data?.items?.length ?? 0, recentTxns: txns.data?.items?.slice(0, 10) };
}
